/**
 * Wraps the OpenNext worker so we can handle Cloudflare Queues on the same Worker.
 * Build artifact: run `npm run build:worker` before `wrangler deploy` / `wrangler dev`.
 */
// @ts-ignore — `.open-next/worker.js` is generated by opennextjs-cloudflare build (not in tsc graph)
import openNextWorker from '../.open-next/worker.js';
import { dispatchQueueBatch, type ReportQueueBatch } from './queue/report-queue-consumer';
import { dispatchDistributionQueueBatch } from './queue/distribution-job-queue-consumer';
import { sendWeeklyReport } from '../services/marketing-attribution/weekly-report';
import { createClient } from '@supabase/supabase-js';
import { structuredError, structuredLog } from '../lib/server/structured-log';
import { createBenchmarkExecutionAdapter } from '../lib/server/benchmark-execution';
import { runScheduledBenchmarkSweep } from '../lib/server/benchmark-schedule';
import { runScheduledDistributionDispatch } from '../lib/server/distribution-job-schedule';
import { runScheduledStartupExecutionDispatch } from '../lib/server/startup-execution-dispatch-schedule';
import { runScheduledStartupSlackAutoPost } from '../lib/server/startup-slack-schedule';
import { runGpmScheduledSweep } from '../lib/server/geo-performance-schedule';
import { buildGpmEntitlementsMap } from '../lib/server/geo-performance-entitlements';
import {
  fetchAndBuildBenchmarkDailyRecap,
  sendBenchmarkDailyRecap,
} from '../lib/server/benchmark-daily-recap';
import {
  resolveSelfImprovementEnvConfig,
  runSelfImprovementAudit,
  type SelfImprovementEnvLike,
} from '../lib/server/self-improvement';
import {
  resolveMarketingAutopilotConfig,
  runMarketingAutopilot,
  type MarketingAutopilotEnvLike,
} from '../lib/server/marketing-autopilot';
import { runDueRecurringAudits, type RecurringEnvLike } from '../lib/server/recurring-audits';
import { runDueOutreach, type OutreachEnvLike } from '../lib/server/outreach';
import { runCompetitorCohortSweep, type CohortEnvLike } from '../lib/server/competitor-cohorts';
import { runDueMonitorAudits } from '../lib/server/monitor-subscription';
import { runEngagementDigest } from '../lib/server/engagement-digest';
import { buildResearchDigestHtml, runResearchSweep } from '../lib/server/research-agent';
import { isAgentEnabled } from '../lib/server/agent-flags';
import { registerSelfFetch } from './lib/fetch-gate';
import { registerLlmVerdictCache } from './scan-engine/run-scan';

/**
 * Route audits of our OWN domain through the self-reference service binding so the scan engine
 * invokes the Worker directly instead of looping out to the origin (which returns HTTP 525).
 */
function registerSelfAuditFetch(env: CloudflareEnv): void {
  try {
    const record = env as unknown as Record<string, unknown>;
    const self = record['WORKER_SELF_REFERENCE'] as { fetch: (input: string) => Promise<Response> } | undefined;
    const appUrl = env.NEXT_PUBLIC_APP_URL;
    if (self && appUrl) {
      registerSelfFetch(new URL(appUrl).hostname, (url) => self.fetch(url));
    } else {
      registerSelfFetch(null, null);
    }
    // Deterministic repeat audits (issue #109): every scan path in this Worker —
    // queue deep audits, recurring, outreach, self-improvement — shares the cache.
    registerLlmVerdictCache(
      (record['SCAN_CACHE'] as Parameters<typeof registerLlmVerdictCache>[0] | undefined) ?? null
    );
  } catch {
    registerSelfFetch(null, null);
  }
}

const next = openNextWorker as {
  fetch: (request: Request, env: CloudflareEnv, ctx: ExecutionContext) => Promise<Response>;
};

function applyDefaultSecurityHeaders(response: Response): Response {
  const headers = new Headers(response.headers);
  const defaults = {
    'strict-transport-security': 'max-age=31536000; includeSubDomains; preload',
    'x-content-type-options': 'nosniff',
    'x-frame-options': 'DENY',
  } as const;

  for (const [key, value] of Object.entries(defaults)) {
    if (!headers.has(key)) {
      headers.set(key, value);
    }
  }

  return new Response(response.body, {
    status: response.status,
    statusText: response.statusText,
    headers,
  });
}

async function pingSupabaseKeepAlive(env: CloudflareEnv): Promise<void> {
  const base = env.NEXT_PUBLIC_SUPABASE_URL?.replace(/\/$/, '') ?? '';
  // Service key first: prod logged supabase_keepalive_failed 401 hourly because the
  // anon key in worker vars no longer authenticates against /rest/v1/, while every
  // service-role cron write works. The ping only exists to keep the project warm.
  const key =
    (env as unknown as Record<string, string>)['SUPABASE_SERVICE_ROLE_KEY'] ||
    env.NEXT_PUBLIC_SUPABASE_ANON_KEY ||
    '';
  if (!base || !key) {
    return;
  }
  const res = await fetch(`${base}/rest/v1/`, {
    headers: {
      apikey: key,
      Authorization: `Bearer ${key}`,
    },
  });
  if (!res.ok) {
    structuredError('supabase_keepalive_failed', { status: res.status });
  }
}

export default {
  async fetch(request: Request, env: CloudflareEnv, ctx: ExecutionContext): Promise<Response> {
    registerSelfAuditFetch(env);
    const response = await next.fetch(request, env, ctx);
    return applyDefaultSecurityHeaders(response);
  },

  async queue(batch: ReportQueueBatch, env: CloudflareEnv, _ctx: ExecutionContext): Promise<void> {
    if (
      batch.queue === 'geo-pulse-distribution-queue' ||
      batch.queue === 'geo-pulse-distribution-dlq'
    ) {
      await dispatchDistributionQueueBatch(batch as any, env);
      return;
    }

    await dispatchQueueBatch(batch, env);
  },

  async scheduled(_event: ScheduledEvent, env: CloudflareEnv, _ctx: ExecutionContext): Promise<void> {
    registerSelfAuditFetch(env);

    // Stage heartbeat (issue #92 follow-up): the hourly handler has died mid-sequence
    // before, silently starving everything after the killer stage. One info log per
    // stage means the LAST heartbeat in app_logs names the stage that ate the tick.
    const cronStartMs = Date.now();
    const stage = (name: string): void => {
      structuredLog('cron_stage', { stage: name, msElapsed: Date.now() - cronStartMs }, 'info');
    };

    try {
      await pingSupabaseKeepAlive(env);
    } catch {
      structuredError('supabase_keepalive_error', {});
    }

    const isMonday = new Date().getUTCDay() === 1;
    const reportTo = (env as unknown as Record<string, string>)['MARKETING_REPORT_TO'] ?? '';
    const resendKey = (env as unknown as Record<string, string>)['RESEND_API_KEY'] ?? '';
    const resendFrom = (env as unknown as Record<string, string>)['RESEND_FROM_EMAIL'] ?? '';
    const supaUrl = env.NEXT_PUBLIC_SUPABASE_URL ?? '';
    const supaKey = (env as unknown as Record<string, string>)['SUPABASE_SERVICE_ROLE_KEY'] ?? '';

    if (isMonday && reportTo && resendKey && resendFrom && supaUrl && supaKey) {
      try {
        const supabase = createClient(supaUrl, supaKey, {
          auth: { persistSession: false, autoRefreshToken: false },
        });
        const result = await sendWeeklyReport({
          supabase,
          resendApiKey: resendKey,
          from: resendFrom,
          to: reportTo,
        });
        if (!result.ok) {
          structuredError('weekly_report_failed', { reason: result.reason });
        }
      } catch (err) {
        structuredError('weekly_report_error', {
          error: err instanceof Error ? err.message : 'unknown',
        });
      }
    }

    if (supaUrl && supaKey) {
      // NOTE (issue #92): the benchmark sweep used to run FIRST here. It fires dozens of
      // external LLM calls and routinely exhausted the invocation, so every job sequenced
      // after it (GPM, recurring audits, outreach, autopilot) silently starved on every
      // tick. Cheap, customer-facing sweeps now run first; the benchmark long-runner and
      // distribution dispatch moved to the END of the handler.
      try {
        const supabase = createClient(supaUrl, supaKey, {
          auth: { persistSession: false, autoRefreshToken: false },
        });
        stage('distribution');
        await runScheduledDistributionDispatch(supabase as any, env as any);
      } catch (err) {
        structuredError('distribution_schedule_worker_error', {
          error: err instanceof Error ? err.message : 'unknown',
        });
      }

      try {
        const supabase = createClient(supaUrl, supaKey, {
          auth: { persistSession: false, autoRefreshToken: false },
        });
        stage('startup_slack');
        await runScheduledStartupSlackAutoPost({
          supabase: supabase as any,
          env: env as any,
        });
      } catch (err) {
        structuredError('startup_slack_schedule_worker_error', {
          error: err instanceof Error ? err.message : 'unknown',
        });
      }

      try {
        const supabase = createClient(supaUrl, supaKey, {
          auth: { persistSession: false, autoRefreshToken: false },
        });
        stage('startup_execution');
        await runScheduledStartupExecutionDispatch({
          supabase: supabase as any,
          env: env as any,
        });
      } catch (err) {
        structuredError('startup_execution_dispatch_worker_error', {
          error: err instanceof Error ? err.message : 'unknown',
        });
      }

      try {
        const supabase = createClient(supaUrl, supaKey, {
          auth: { persistSession: false, autoRefreshToken: false },
        });
        const envRecord = env as unknown as Record<string, string | undefined>;
        stage('gpm');
        const gpmEnv = {
          GPM_SCHEDULE_ENABLED:    envRecord['GPM_SCHEDULE_ENABLED'],
          GPM_CHATGPT_MODEL_ID:    envRecord['GPM_CHATGPT_MODEL_ID'],
          GPM_GEMINI_MODEL_ID:     envRecord['GPM_GEMINI_MODEL_ID'],
          GPM_PERPLEXITY_MODEL_ID: envRecord['GPM_PERPLEXITY_MODEL_ID'],
          GPM_ENABLED_PLATFORMS:   envRecord['GPM_ENABLED_PLATFORMS'],
          ANTHROPIC_API_KEY:       envRecord['ANTHROPIC_API_KEY'],
          GPM_NARRATIVE_MODEL:     envRecord['GPM_NARRATIVE_MODEL'],
          // Gemini narrative fallback (used when no ANTHROPIC_API_KEY). Falls back to
          // the benchmark Gemini key so the narrative works with zero extra config.
          GEMINI_API_KEY:          envRecord['GEMINI_API_KEY'] ?? envRecord['BENCHMARK_EXECUTION_API_KEY'],
          GPM_NARRATIVE_GEMINI_MODEL: envRecord['GPM_NARRATIVE_GEMINI_MODEL'],
          GEMINI_ENDPOINT:         envRecord['GEMINI_ENDPOINT'],
          GPM_REPORT_R2_PUBLIC_BASE: envRecord['GPM_REPORT_R2_PUBLIC_BASE'],
          RESEND_API_KEY:          resendKey || undefined,
          RESEND_FROM_EMAIL:       resendFrom || undefined,
        };
        const { data: configStubs } = await supabase
          .from('client_benchmark_configs')
          .select('id, startup_workspace_id, agency_account_id');
        const entitlementsMap = await buildGpmEntitlementsMap(supabase, configStubs ?? []);
        await runGpmScheduledSweep({
          supabase,
          env: gpmEnv,
          entitlementsByConfigId: entitlementsMap,
          adapter: createBenchmarkExecutionAdapter(env),
          triggerSource: 'worker_cron',
          reportBucket: (env as any).REPORT_FILES,
        });
      } catch (err) {
        structuredError('gpm_schedule_worker_error', {
          error: err instanceof Error ? err.message : 'unknown',
        });
      }

      // Daily autonomous self-improvement audit (Loop 5a) — gated to fire once per day at
      // SELF_IMPROVEMENT_HOUR_UTC (default 12:00 UTC, which maps to a real cron tick). The
      // audit self-gates on env flag + DB `enabled` + kill switch + a configured recipient, so
      // this is a safe no-op until explicitly turned on.
      try {
        const selfEnv = env as unknown as SelfImprovementEnvLike;
        const selfCfg = resolveSelfImprovementEnvConfig(selfEnv);
        stage('self_improvement');
        if (new Date().getUTCHours() === selfCfg.hourUtc) {
          const supabase = createClient(supaUrl, supaKey, {
            auth: { persistSession: false, autoRefreshToken: false },
          });
          const result = await runSelfImprovementAudit({
            supabase,
            env: selfEnv,
            triggerSource: 'worker_cron',
          });
          if (result.status !== 'skipped') {
            structuredLog('self_improvement_cron_run', {
              status: result.status,
              score: result.score ?? null,
              emailed: result.emailed ?? false,
              reason: result.reason ?? null,
            }, result.ok ? 'info' : 'error');
          }
        }
      } catch (err) {
        structuredError('self_improvement_cron_error', {
          error: err instanceof Error ? err.message : 'unknown',
        });
      }

      // Admin Research Agent (spec §8) — weekly Monday sweep of the authoritative source
      // watchlist. Draft-only: it queues proposals for human review and never touches any
      // scan, report, or config path. Quiet no-op until migration 055 is applied.
      try {
        stage('research');
        const researchDue = isMonday && new Date().getUTCHours() === 14;
        const researchSupabase = researchDue
          ? createClient(supaUrl, supaKey, { auth: { persistSession: false, autoRefreshToken: false } })
          : null;
        if (
          researchDue &&
          researchSupabase &&
          (await isAgentEnabled(researchSupabase, 'research_agent', { failOpen: true }))
        ) {
          const supabase = researchSupabase;
          const digestTo = (env as unknown as Record<string, string>)['MARKETING_REPORT_TO'] ?? '';
          const sweep = await runResearchSweep({
            supabase,
            ai: (env as unknown as { AI?: { run: (m: string, i: Record<string, unknown>) => Promise<unknown> } }).AI ?? null,
            nowMs: Date.now(),
            notify:
              digestTo && resendKey && resendFrom
                ? async ({ proposals }) => {
                    await fetch('https://api.resend.com/emails', {
                      method: 'POST',
                      headers: { 'Content-Type': 'application/json', Authorization: `Bearer ${resendKey}` },
                      body: JSON.stringify({
                        from: resendFrom,
                        to: digestTo,
                        subject: `Research agent: ${String(proposals.length)} source change(s) to review`,
                        html: buildResearchDigestHtml(proposals),
                      }),
                    });
                  }
                : undefined,
          });
          if (sweep.checked > 0) {
            structuredLog('research_sweep_tick', { ...sweep }, 'info');
          }
        }
      } catch (err) {
        structuredError('research_sweep_error', {
          error: err instanceof Error ? err.message : 'unknown',
        });
      }

      // Outreach v1 — recurring scorecard emails to admin-added prospects (no account needed).
      // Self-gates on `next_run_at`; a tick with nothing due is a cheap no-op.
      // Admin-flagged (fail-open): a row in automation_settings can switch it off.
      // Engagement digest (issue #131): daily 12:00 UTC ping to the operator, only when the
      // last 24h had funnel activity. Cheap (a few reads), so it runs before the heavy stages.
      try {
        const supabase = createClient(supaUrl, supaKey, {
          auth: { persistSession: false, autoRefreshToken: false },
        });
        stage('engagement_digest');
        const digest = await runEngagementDigest({
          supabase,
          env: env as unknown as { RESEND_API_KEY?: string; RESEND_FROM_EMAIL?: string },
          nowMs: Date.now(),
        });
        if (digest.sent) {
          structuredLog('engagement_digest_tick', { sent: true }, 'info');
        }
      } catch (err) {
        structuredError('engagement_digest_error', {
          error: err instanceof Error ? err.message : 'unknown',
        });
      }

      try {
        const supabase = createClient(supaUrl, supaKey, {
          auth: { persistSession: false, autoRefreshToken: false },
        });
        stage('outreach');
        const result = (await isAgentEnabled(supabase, 'outreach_sweep', { failOpen: true }))
          ? await runDueOutreach({
              supabase,
              env: env as unknown as OutreachEnvLike,
              nowMs: Date.now(),
            })
          : { scanned: 0, ran: 0, failed: 0 };
        if (result.scanned > 0) {
          structuredLog('outreach_sweep_tick', {
            scanned: result.scanned,
            ran: result.ran,
            failed: result.failed,
          }, 'info');
        }
      } catch (err) {
        structuredError('outreach_sweep_error', {
          error: err instanceof Error ? err.message : 'unknown',
        });
      }

      // Daily autonomous marketing autopilot (Loop 5b) — gated once per day at
      // MARKETING_AUTOPILOT_HOUR_UTC (default 13:00 UTC). Proposes review-gated content briefs
      // for weak (uncovered) topics; never publishes. Self-gates on env flag + kill switch, so
      // this is a safe no-op until explicitly enabled.
      try {
        const mktEnv = env as unknown as MarketingAutopilotEnvLike;
        const mktCfg = resolveMarketingAutopilotConfig(mktEnv);
        if (new Date().getUTCHours() === mktCfg.hourUtc) {
          const supabase = createClient(supaUrl, supaKey, {
            auth: { persistSession: false, autoRefreshToken: false },
          });
          stage('marketing_autopilot');
          const result = await runMarketingAutopilot({
            supabase,
            env: mktEnv,
            triggerSource: 'worker_cron',
          });
          if (result.status !== 'skipped') {
            structuredLog('marketing_autopilot_cron_run', {
              status: result.status,
              batch: result.batch ?? null,
              proposed: result.proposedCount ?? 0,
              channel_access: result.channelAccess ?? null,
              reason: result.reason ?? null,
            }, result.ok ? 'info' : 'error');
          }
        }
      } catch (err) {
        structuredError('marketing_autopilot_cron_error', {
          error: err instanceof Error ? err.message : 'unknown',
        });
      }

      // Recurring per-user site audits (Phase 3) — runs any schedule that's due this tick.
      // Self-gates on `next_run_at`. Runs AFTER outreach/research/autopilot deliberately:
      // its self-domain audit hung an entire invocation for hours (2026-07-21), and the
      // lead-gen sweeps must never pay for that again.
      try {
        const supabase = createClient(supaUrl, supaKey, {
          auth: { persistSession: false, autoRefreshToken: false },
        });
        stage('recurring_audits');
        const result = await runDueRecurringAudits({
          supabase,
          env: env as unknown as RecurringEnvLike,
          nowMs: Date.now(),
        });
        if (result.scanned > 0) {
          structuredLog('recurring_audits_sweep', {
            scanned: result.scanned,
            ran: result.ran,
            failed: result.failed,
            fed_self_improvement: result.fedSelfImprovement,
          }, 'info');
        }
      } catch (err) {
        structuredError('recurring_audits_sweep_error', {
          error: err instanceof Error ? err.message : 'unknown',
        });
      }

      // Monitoring subscribers ($39/mo) — re-audit due sites and email the monthly report. Paying
      // customers, so this runs before the internal cohort/benchmark long-runners. Bounded to a
      // couple scans per tick to respect the Free-plan CPU budget (same constraint as the cohort).
      try {
        const supabase = createClient(supaUrl, supaKey, {
          auth: { persistSession: false, autoRefreshToken: false },
        });
        stage('monitor_audits');
        const result = await runDueMonitorAudits({
          supabase,
          env: env as unknown as RecurringEnvLike,
          nowMs: Date.now(),
          // Workers Paid: 5-min CPU ceiling lets several re-audits run per tick (paying subscribers).
          limit: 5,
        });
        if (result.due > 0) {
          structuredLog('monitor_audits_tick', { due: result.due, ran: result.ran, failed: result.failed }, 'info');
        }
      } catch (err) {
        structuredError('monitor_audits_error', { error: err instanceof Error ? err.message : 'unknown' });
      }

      // Local-competitor cohort sweep (issue #118) — FAIL-CLOSED flag; every fetch inside
      // runFreeScan is timeout-bounded (~65s worst case per scan). Sits with the benchmark
      // long-runner at the tail so customer-facing stages never wait on it.
      try {
        const supabase = createClient(supaUrl, supaKey, {
          auth: { persistSession: false, autoRefreshToken: false },
        });
        stage('competitor_cohort');
        const result = await runCompetitorCohortSweep({
          supabase,
          env: env as unknown as CohortEnvLike,
          nowMs: Date.now(),
          // Workers Paid: 5-min CPU ceiling clears several cohort sites per tick — enough to
          // re-audit all 202 domains well within a week instead of one per hour.
          maxScans: 5,
        });
        if (result.enabled && result.due > 0) {
          structuredLog('competitor_cohort_tick', {
            due: result.due,
            scanned: result.scanned,
            failed: result.failed,
          }, 'info');
        }
      } catch (err) {
        structuredError('competitor_cohort_error', {
          error: err instanceof Error ? err.message : 'unknown',
        });
      }

      // Benchmark schedule sweep — the long-runner (many external LLM calls). Runs LAST
      // deliberately (issue #92): if it exhausts the invocation, nothing else is starved.
      try {
        const supabase = createClient(supaUrl, supaKey, {
          auth: { persistSession: false, autoRefreshToken: false },
        });
        stage('benchmark');
        await runScheduledBenchmarkSweep({
          supabase,
          env,
          adapter: createBenchmarkExecutionAdapter(env),
          triggerSource: 'worker_cron',
        });
      } catch (err) {
        structuredError('benchmark_schedule_worker_error', {
          error: err instanceof Error ? err.message : 'unknown',
        });
      }

      // Daily benchmark recap email — gated so exactly one recap fires per day at
      // HOUR_LOCAL in the configured TIMEZONE (DST-aware). The cron schedule
      // covers all UTC offsets that map to that local hour year-round; this gate
      // picks the right one. Skipped when no recipient or Resend key is configured.
      const envRecord = env as unknown as Record<string, string | undefined>;
      stage('recap');
      const recapTo = envRecord['BENCHMARK_DAILY_RECAP_TO'];
      const recapHourRaw = envRecord['BENCHMARK_DAILY_RECAP_HOUR_LOCAL'];
      const recapHour = Number.parseInt(recapHourRaw ?? '19', 10);
      const recapHourGate = Number.isFinite(recapHour) ? recapHour : 19;
      const recapTimezone = envRecord['BENCHMARK_DAILY_RECAP_TIMEZONE'] ?? 'America/Toronto';
      const recapVertical = envRecord['BENCHMARK_SCHEDULE_VERTICAL'] ?? 'marketing_firms';

      let currentLocalHour: number;
      try {
        currentLocalHour = Number.parseInt(
          new Intl.DateTimeFormat('en-US', {
            timeZone: recapTimezone,
            hour: 'numeric',
            hour12: false,
          }).format(new Date()),
          10
        );
      } catch {
        // Bad timezone string — fall back to UTC so we still fire predictably.
        currentLocalHour = new Date().getUTCHours();
      }

      if (recapTo && resendKey && resendFrom && currentLocalHour === recapHourGate) {
        try {
          const supabase = createClient(supaUrl, supaKey, {
            auth: { persistSession: false, autoRefreshToken: false },
          });
          const recap = await fetchAndBuildBenchmarkDailyRecap({
            supabase,
            vertical: recapVertical,
            now: new Date(),
          });
          const result = await sendBenchmarkDailyRecap({
            recap,
            resendApiKey: resendKey,
            from: resendFrom,
            to: recapTo,
          });
          if (!result.ok) {
            structuredError('benchmark_daily_recap_send_failed', { reason: result.reason });
          } else {
            structuredLog('benchmark_daily_recap_sent', {
              to: recapTo,
              vertical: recapVertical,
              timezone: recapTimezone,
              local_hour: currentLocalHour,
              completed_runs: recap.runStatus.completed,
              failed_runs: recap.runStatus.failed,
              total_citations: recap.totalCitations,
              cited_domains: recap.distinctDomainsCited,
            });
          }
        } catch (err) {
          structuredError('benchmark_daily_recap_error', {
            error: err instanceof Error ? err.message : 'unknown',
          });
        }
      }
    }
  },
};
